import{_ as i,M as h,p as r,q as o,R as t,t as e,N as s,a1 as a}from"./framework-e0dd9823.js";const l={},n=t("h1",{id:"代词",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#代词","aria-hidden":"true"},"#"),e(" 代词")],-1),p={href:"https://zh.wikipedia.org/wiki/%E4%BB%A3%E8%A9%9E",target:"_blank",rel:"noopener noreferrer"},c=a('<p>在对话中，人们一般不喜欢重复的使用名词，例如“这只鸡长得很好看，它已经养了两年半了”，这句话中的“它”就是代替上文的这只鸡。所以代词的主要作用就是代替名词。</p><p>英语中的代词有九种：人称代词、物主代词、指示代词、反身代词、相互代词、不定代词、疑问代词、连接代词、关系代词</p><p>代词的格式：</p><table><thead><tr><th>中文意思</th><th>我</th><th>你</th><th>他</th><th>她</th><th>它</th><th>我们</th><th>他们/她们/它们</th></tr></thead><tbody><tr><td>主格</td><td>I</td><td>You</td><td>He</td><td>She</td><td>It</td><td>We</td><td>They</td></tr><tr><td>宾格</td><td>me</td><td>you</td><td>him</td><td>her</td><td>it</td><td>us</td><td>them</td></tr><tr><td>形容词性物主代词</td><td>my</td><td>your</td><td>his</td><td>her</td><td>its</td><td>our</td><td>their</td></tr><tr><td>名词词性物主代词</td><td>mine</td><td>yours</td><td>his</td><td>hers</td><td>its</td><td>ours</td><td>theirs</td></tr></tbody></table><h2 id="人称代词" tabindex="-1"><a class="header-anchor" href="#人称代词" aria-hidden="true">#</a> 人称代词</h2><p>人称代词一般代替表示人的名词，例如“Newton”是一个表示人的名词，为了避免重复出现这个名字就可以用“He”来代替人名“Newton”。在英语中，如果出现大量相同的名词，必须使用代词。</p><p>例如：“Nick is a teacher, Nick is form Xi&#39;an, Nick is very old”，这种情况下必须使用“Nick is a teacher, He is form Xi&#39;an, He is very old”。</p><p>人称代词在句子中的作用：</p><ol><li>作主语，人称代词主格在句子中作主语，例如“I like English”；</li></ol><p>如果多个人称代词主格单数作并列作主语，要注意顺序：You, he/she and I</p><p>复数顺序：We, you and they</p><ol start="2"><li>作宾语，人称代词宾格在句子中作宾语，例如“They like me”； 3. 作表语，主格和宾格都可以，例如“It is me”或者“It is I”；</li></ol><h2 id="物主代词" tabindex="-1"><a class="header-anchor" href="#物主代词" aria-hidden="true">#</a> 物主代词</h2><p>物主代词分为两种：形容词性物主代词和名词性物主代词，它们两个在中文意思上都是“什么的”，例如“my”和“mine”都表示我的，但是在用法上缺截然不同。这里用一句中文来解释一些它们。“我的房子很大”，这里“我的”在英语中就是形容词性物主代词，它是用来作定语的。“这个房子是我的”，这里的“我的”就是名词性物主代词，它是用来指代名词，表示“我的房子”。</p><ol><li>形容词性物主代词，表示所属关系或者所有关系，主要用来作前置定语</li></ol><p>例句：My book is new / My T-shirt is skyblue</p><ol start="2"><li>名词性物主代词，为了避免重复代替前面出现的名词的代词，它可以充当主语、表语、宾语、介词宾语等作用。使用名词性物主代词的时候必须在句子前面提到过的名词或者有相应的语境才可以使用。</li></ol><p>例句：</p><ul><li>My computer is better than yours 我的电脑比你的（电脑）好</li><li>My house is bigger than yours 我的房子比你的（房子）大</li></ul><p>注意：名词性物主代词不可以作定语。例如“My book”不能写成“Mine book”</p><h2 id="指示代词" tabindex="-1"><a class="header-anchor" href="#指示代词" aria-hidden="true">#</a> 指示代词</h2><table><thead><tr><th>单数</th><th>复数</th></tr></thead><tbody><tr><td>this 这个</td><td>these 这些</td></tr><tr><td>that 那个</td><td>those 那些</td></tr></tbody></table><p>“this”指较近的人或物，“that”指较远的人或物</p><p>作用：</p><ol><li><p>作前置定语，“this”和“that”修饰可数名词单数或者不可数名词（用法较少），例如：This house、That house、This girl、That girl；“these”和“those”修饰可数名词复数，例如 these hoses、those girl</p></li><li><p>作主语、宾语、表语，这个时候是一个真正意义上的名词，例如：</p></li></ol><ul><li>This is my book</li><li>That is my student</li><li>I want this（作宾语，这个时候“this”一定要是大家都知道是什么的情况下）</li><li>It is this（作表语，就是这个，同上）</li></ul><p>注意：受到中文发音习惯的影响，很多人会将代词的主格和形容词性物主代词搞混淆。例如大家唱说“我哥”、“我姐”、“你爸”这种，在中文口语中这么表达没有问题，但是如果直接翻译英语“I brother”就是错误的。我中我们想要表达的意识应该是“我的哥哥”，翻译成英语应该是“My brother”，英语中人称代词主格是不能作定语的。</p>',27);function u(y,b){const d=h("ExternalLinkIcon");return r(),o("div",null,[n,t("blockquote",null,[t("p",null,[e("代词（英语：pronoun），又叫代名词，在语言学和语法学中是指代替名词或名词短语的形式词（是否附加限定词各个语言不同），如汉语的“你”、“我”、“他”，英语的“you”、“this”，法语的“nous”、“elle”等。问句中代替被询问物体的代词叫做疑问代词，比如“谁”等。"),t("a",p,[e("维基百科"),s(d)])])]),c])}const _=i(l,[["render",u],["__file","pronouns.html.vue"]]);export{_ as default};
